12	  countNeighbors(x: number, y: number): number {
13	    let count = 0;
14	    for (let dx = -1; dx <= 1; dx++) {
15	      for (let dy = -1; dy <= 1; dy++) {
16	        if (dx === 0 && dy === 0) continue;
17	        const nx = x + dx;
18	        const ny = y + dy;
19	        if (this.cells.some(cell => cell[0] === nx && cell[1] === ny)) {
